const input = items[0].json.body;

const defensaId = input.defensaId;
const templateGoogleDocId = input.templateGoogleDocId;
const midias = input.midias || [];

function getTipoMidia(nome, url) {
  const lower = (nome || url || "").toLowerCase();

  if (lower.endsWith(".pdf")) return "pdf";

  if (
    lower.endsWith(".jpg") ||
    lower.endsWith(".jpeg") ||
    lower.endsWith(".png") ||
    lower.endsWith(".gif") ||
    lower.endsWith(".webp")
  ) return "img";

  return "outro";
}

// 🚀 AGORA PREPARADO PRA ARQUITETURA CORRETA
return midias.map((m, index) => {
  const tipo = getTipoMidia(m.nome, m.url);

  return {
    json: {
      defensaId,
      templateGoogleDocId,

      // 🔑 ESSENCIAL PRA NÃO PERDER CONTEXTO NO FLUXO
      midiaIndex: index,

      url: m.url,
      nome: m.nome,
      tipo,
      principal: m.principal || false,

      // 🔥 flags úteis pro fluxo (evita IF complexo depois)
      isPdf: tipo === "pdf",
      isImg: tipo === "img",

      // 🔥 controle de fluxo
      origem: "upload",

      // 🔥 prepara campos que vão existir depois (padronização)
      pageIndex: null,
      totalPages: null
    }
  };
});

const allItems = items;

let urlDataprev = null;

function extrairTextoEUrl(item) {
  let textos = [];

  // 🔥 OCR (formato merge "0")
  if (item.json["0"]?.content?.[0]?.text) {
    const raw = item.json["0"].content[0].text;

    // 🔥 extrai URL CORRETA do OCR
    let url = null;

    const labeledUrl = raw.match(/URL.*?:\s*(https?:\/\/[^\s]+)/i);
    if (labeledUrl) {
      url = labeledUrl[1];
    } else {
      const allUrls = raw.match(/https?:\/\/[^\s]+/g);
      if (allUrls && allUrls.length > 0) {
        url = allUrls[allUrls.length - 1];
      }
    }

    // 🔥 remove URL do texto
    const textoLimpo = raw
      .replace(/```/g, "")
      .replace(/https?:\/\/[^\s]+/g, "")
      .replace(/\*\*URL do arquivo:\*\*/gi, "")
      .trim();

    // 🔥 DETECTA DATAPREV
    const lower = textoLimpo.toLowerCase();

    const isDataprev =
      lower.includes("nb:") &&
      lower.includes("cpf:") &&
      lower.includes("espécie") &&
      lower.includes("dt. início");

    if (isDataprev && url) {
      urlDataprev = url;
    }

    textos.push(textoLimpo);
  }

  // 🔥 OCR formato antigo
  if (Array.isArray(item.json) && item.json[0]?.content?.[0]?.text) {
    textos.push(item.json[0].content[0].text);
  }

  // 🔥 PDF extractor
  if (Array.isArray(item.json.text)) {
    textos.push(item.json.text.join("\n"));
  }

  // 🔥 fallback
  if (item.json.textoExtraido) {
    textos.push(item.json.textoExtraido);
  }

  return textos.join("\n\n");
}

// ordena
allItems.sort((a, b) => (a.json.pageIndex || 0) - (b.json.pageIndex || 0));

// extrai textos
const textos = allItems
  .map(item => extrairTextoEUrl(item))
  .filter(t => t && t.trim().length > 0);

// junta tudo
const textoCompleto = textos.join("\n\n");

// datas
const hoje = new Date();

const dataSubmissao = hoje.toLocaleDateString("pt-BR");

const dataIdentificacao = hoje.toLocaleDateString("pt-BR", {
  month: "long",
  year: "numeric"
});

// retorno final
return [
  {
    json: {
      textoCompleto,
      urlDataprev, // 🔥 AQUI ESTÁ O OURO
      dataSubmissao,
      dataIdentificacao
    }
  }
];

