(() => {
  const data = $('Normaliza os campos').first().json.DATA_SUBMISSAO;

  const meses = {
    janeiro: '01',
    fevereiro: '02',
    março: '03',
    abril: '04',
    maio: '05',
    junho: '06',
    julho: '07',
    agosto: '08',
    setembro: '09',
    outubro: '10',
    novembro: '11',
    dezembro: '12'
  };

  const match = data.match(/(\d{1,2}) de (\w+) de (\d{4})/i);

  if (!match) return null;

  const dia = match[1].padStart(2, '0');
  const mes = meses[match[2].toLowerCase()];
  const ano = match[3];

  return `${ano}-${mes}-${dia}`;
})()
}}

